mapper.select:
SELECT
* , st_astext(_geometry) as geometry_wkt , st_area(_geometry) as geometry_area , st_length(_geometry) as geometry_length , st_x(st_centroid(st_transform(_geometry, 4326))) as geometry_lon , st_y(st_centroid(st_transform(_geometry, 4326))) as geometry_lat
FROM ${st.schema}.${st.table}
WHERE
"${featureKv.fieldKey}" = #{featureKv.fieldVal}::numeric "${featureKv.fieldKey}" = #{featureKv.fieldVal}
_gid = #{pk}

		CREATE TABLE ${st.newSchema}.${st.newTable} AS

		SELECT

			a.*

        FROM ${st.schema}.${st.table} AS a




					AND "${map.key}" = #{map.val}::numeric

					AND LOWER("${map.key}") LIKE '%' || LOWER(#{map.val}) || '%'





					AND ST_INTERSECTS(
						( SELECT ST_GeomFromText(#{spatialSt.wkt}, 5186) ), a._geometry
					)





		; COMMENT ON TABLE ${st.newSchema}.${st.newTable} IS '${st.layerNm}';

			COMMENT ON COLUMN ${st.newSchema}.${st.newTable}."${typ.col}" IS '${typ.nm}';


		ALTER TABLE ${st.newSchema}.${st.newTable} ADD CONSTRAINT ${st.newTable}_pk PRIMARY KEY (_gid);
		CREATE INDEX ${st.newSchema}_${st.newTable}__geometry ON ${st.newSchema}.${st.newTable} USING gist (_geometry);


		CREATE SEQUENCE ${st.newSchema}.${st.newTable}__gid_seq INCREMENT 1 MINVALUE 1 MAXVALUE 9223372036854775807 START 1 CACHE 1;
		SELECT SETVAL('${st.newSchema}.${st.newTable}__gid_seq',(SELECT MAX(_gid) FROM ${st.newSchema}.${st.newTable}));

		ALTER TABLE ${st.newSchema}.${st.newTable} ALTER COLUMN _gid SET DEFAULT nextval('${st.newSchema}.${st.newTable}__gid_seq');
		ALTER SEQUENCE "${st.newSchema}".${st.newTable}__gid_seq OWNED BY ${st.newSchema}.${st.newTable}._gid
